// ═══════════════════════════════════════════════════════════════
// PRE-BUILD: Plants (365 max, grid-distributed)
//   Plant i appears day i+1, flowers day i+2
//   Split: far bank above river and near bank below river
// ═══════════════════════════════════════════════════════════════
function prebuildPlants() {
    const plants = [];
    const cols = 18, rowsFar = 4, rowsNear = 7;
    let idx = 0;

    // Far bank plants (behind river)
    for (let r = 0; r < rowsFar && idx < 365; r++) {
        for (let c = 0; c < cols && idx < 365; c++, idx++) {
            const seed = idx * 137 + 3;
            plants.push({
                nx: groveX(0.05 + (c + 0.25 + sr(seed) * 0.5) / cols * 0.9),
                ny: groveY(0.34 + (r + 0.25 + sr(seed + 1) * 0.5) / rowsFar * 0.22),
                flowerColor: FLOWER_COLORS[Math.floor(sr(seed + 2) * FLOWER_COLORS.length)],
                stemH: 8 + sr(seed + 3) * 10,
                flowerSize: 4 + sr(seed + 4) * 4,
                swayOff: sr(seed + 5) * Math.PI * 2,
                swaySpd: 0.012 + sr(seed + 6) * 0.015,
                depth: 0.18 + sr(seed + 7) * 0.2,
                bank: 'far',
                day: idx + 1,
            });
        }
    }

    // Near bank plants (in front of river)
    for (let r = 0; r < rowsNear && idx < 365; r++) {
        for (let c = 0; c < cols && idx < 365; c++, idx++) {
            const seed = idx * 137 + 3;
            plants.push({
                nx: groveX(0.05 + (c + 0.25 + sr(seed) * 0.5) / cols * 0.9),
                ny: groveY(0.68 + (r + 0.25 + sr(seed + 1) * 0.5) / rowsNear * 0.24),
                flowerColor: FLOWER_COLORS[Math.floor(sr(seed + 2) * FLOWER_COLORS.length)],
                stemH: 9 + sr(seed + 3) * 12,
                flowerSize: 4 + sr(seed + 4) * 5,
                swayOff: sr(seed + 5) * Math.PI * 2,
                swaySpd: 0.012 + sr(seed + 6) * 0.015,
                depth: 0.3 + sr(seed + 7) * 0.35,
                bank: 'near',
                day: idx + 1,
            });
        }
    }
    return plants;
}

// ═══════════════════════════════════════════════════════════════
// PRE-BUILD: Trees (max 52, one per 7 days)
//   Tree i planted day (i+1)*7, fruits day (i+2)*7
//   Far side above river, near side below river
// ═══════════════════════════════════════════════════════════════
function prebuildTrees() {
    const trees = [];
    for (let i = 0; i < 52; i++) {
        const seed = i * 211 + 7;
        const isFar = i % 3 !== 0; // 2/3 far, 1/3 near
        const row = Math.floor(i / 9);
        const col = i % 9;
        const nx = groveX(0.08 + (col + 0.18 + sr(seed) * 0.48) / 9 * 0.84);
        const ny = isFar
            ? groveY(0.18 + (row % 3) * 0.09 + sr(seed + 1) * 0.035)
            : groveY(0.58 + (row % 3) * 0.10 + sr(seed + 1) * 0.04);

        trees.push({
            nx,
            ny,
            trunkH: 24 + sr(seed + 2) * 22,
            trunkW: 5 + sr(seed + 3) * 5,
            canopyR: 18 + sr(seed + 4) * 17,
            hue: 90 + sr(seed + 5) * 50,
            sat: 45 + sr(seed + 6) * 30,
            lit: 28 + sr(seed + 7) * 18,
            fruitHue: sr(seed + 8) * 360,
            fruitCount: 2 + Math.floor(sr(seed + 9) * 4),
            swayOff: sr(seed + 10) * Math.PI * 2,
            depth: isFar ? 0.12 + sr(seed + 11) * 0.15 : 0.3 + sr(seed + 11) * 0.3,
            plantedDay: (i + 1) * 7,
            bank: isFar ? 'far' : 'near',
        });
    }
    trees.sort((a, b) => a.ny - b.ny);
    return trees;
}

// ═══════════════════════════════════════════════════════════════
// PRE-BUILD: Animals (12, specific unlock days)
// ═══════════════════════════════════════════════════════════════
function prebuildAnimals() {
    return ANIMAL_DEFS.map((a, i) => {
        const seed = i * 311 + 13;
        const isFish = a.name === 'Fish';
        const isFrog = a.name === 'Frog';
        let ny, nx;
        if (isFish) {
            nx = groveX(0.16 + sr(seed) * 0.64);
            ny = groveY(0.58 + sr(seed + 1) * 0.05);
        } else if (isFrog) {
            nx = groveX(0.22 + sr(seed) * 0.46);
            ny = groveY(0.66 + sr(seed + 1) * 0.04);
        } else {
            nx = groveX(0.14 + sr(seed) * 0.68);
            ny = groveY(0.70 + sr(seed + 1) * 0.18);
        }
        return {
            ...a,
            nx, ny,
            size: a.name === 'Ant' ? 10 : a.name === 'Bee' ? 12 : a.name === 'Spider' ? 10 : a.name === 'Locust' ? 12 : 17 + sr(seed + 2) * 9,
            depth: isFish ? 0.18 : isFrog ? 0.28 : 0.32 + sr(seed + 3) * 0.25,
            idleOff: sr(seed + 4) * Math.PI * 2,
            idleSpd: 0.015 + sr(seed + 5) * 0.02,
        };
    });
}

