// PRE-BUILD: River stones
// ═══════════════════════════════════════════════════════════════
function prebuildStones() {
    const stones = [];
    for (let i = 0; i < 9; i++) {
        const seed = i * 57 + 99;
        stones.push({
            nx: groveX(0.10 + sr(seed) * 0.78),
            ny: groveY(0.58 + sr(seed + 1) * 0.05),
            rx: 4 + sr(seed + 2) * 8,
            ry: 2.5 + sr(seed + 3) * 4,
            rot: sr(seed + 4) * Math.PI,
            shade: 0.3 + sr(seed + 5) * 0.25,
        });
    }
    return stones;
}

// ═══════════════════════════════════════════════════════════════
// DRAW HELPERS
// ═══════════════════════════════════════════════════════════════

function toScreen(nx, ny, depth, W, H, camX, camY) {
    return [nx * W - camX * depth, ny * H - camY * depth];
}

function drawGround(ctx, W, H, camX, camY) {
    ctx.fillStyle = '#25421f';
    ctx.fillRect(0, 0, W, H);

    const x = GROVE.x0 * W - camX * 0.04;
    const y = GROVE.y0 * H - camY * 0.04;
    const w = (GROVE.x1 - GROVE.x0) * W;
    const h = (GROVE.y1 - GROVE.y0) * H;

    const nearG = ctx.createLinearGradient(0, y, 0, y + h);
    nearG.addColorStop(0, '#668f4b');
    nearG.addColorStop(0.45, '#5b8841');
    nearG.addColorStop(1, '#3d6c32');
    ctx.fillStyle = nearG;
    ctx.beginPath();
    ctx.roundRect(x, y, w, h, 18);
    ctx.fill();

    ctx.save();
    ctx.globalAlpha = 0.22;
    ctx.fillStyle = '#203817';
    ctx.beginPath();
    ctx.ellipse(x + w * 0.48, y + h * 0.94, w * 0.46, h * 0.08, 0, 0, Math.PI * 2);
    ctx.fill();
    ctx.restore();
}

function drawGrassTufts(ctx, W, H, frame, camX, camY, yMin, yMax, count, seed) {
    ctx.save();
    ctx.globalAlpha = 0.4;
    ctx.strokeStyle = '#3a6a28';
    ctx.lineWidth = 1;
    for (let i = 0; i < count; i++) {
        const s = seed + i * 31;
        const nx = groveX(0.04 + sr(s) * 0.9);
        const ny = yMin + sr(s + 1) * (yMax - yMin);
        const [x, y] = toScreen(nx, ny, 0.35, W, H, camX, camY);
        if (x < -20 || x > W + 20) continue;
        const h = 5 + sr(s + 2) * 8;
        const sway = Math.sin(frame * 0.02 + s) * 2;
        ctx.beginPath();
        ctx.moveTo(x, y);
        ctx.quadraticCurveTo(x + sway, y - h * 0.6, x + sway * 1.5, y - h);
        ctx.stroke();
        ctx.beginPath();
        ctx.moveTo(x + 3, y);
        ctx.quadraticCurveTo(x + 3 - sway * 0.5, y - h * 0.5, x + 3 - sway, y - h * 0.85);
        ctx.stroke();
    }
    ctx.restore();
}

function drawRiver(ctx, W, H, frame, camX, camY, stones) {
    const [rx1, ry1] = toScreen(groveX(0.06), groveY(0.57), 0.15, W, H, camX, camY);
    const [rx2, ry2] = toScreen(groveX(0.91), groveY(0.65), 0.15, W, H, camX, camY);
    const rTop = ry1;
    const rBot = ry2;
    const rH = rBot - rTop;
    const rLeft = rx1;
    const rRight = rx2;
    const rW = rRight - rLeft;

    // Water body
    const wg = ctx.createLinearGradient(0, rTop, 0, rBot);
    wg.addColorStop(0, '#3a8ab0');
    wg.addColorStop(0.3, '#2a7aa5');
    wg.addColorStop(0.7, '#1a6a95');
    wg.addColorStop(1, '#2a7aa0');
    ctx.fillStyle = wg;
    ctx.beginPath();
    ctx.moveTo(rLeft, rTop + rH * 0.2);
    ctx.bezierCurveTo(rLeft + rW * 0.25, rTop - rH * 0.05, rLeft + rW * 0.5, rTop + rH * 0.25, rRight, rTop);
    ctx.lineTo(rRight, rBot - rH * 0.15);
    ctx.bezierCurveTo(rLeft + rW * 0.68, rBot + rH * 0.18, rLeft + rW * 0.3, rBot - rH * 0.15, rLeft, rBot);
    ctx.closePath();
    ctx.fill();

    // Wave lines
    ctx.save();
    ctx.globalAlpha = 0.25;
    ctx.strokeStyle = '#a0d8f0';
    ctx.lineWidth = 1;
    for (let row = 0; row < 5; row++) {
        const wy = rTop + rH * (0.15 + row * 0.17);
        ctx.beginPath();
        for (let x = rLeft + 8; x <= rRight - 8; x += 4) {
            const wave = Math.sin(x * 0.02 + frame * 0.03 + row * 2) * 2.5;
            x === rLeft + 8 ? ctx.moveTo(x, wy + wave) : ctx.lineTo(x, wy + wave);
        }
        ctx.stroke();
    }
    ctx.restore();

    // Shimmer highlights
    ctx.save();
    for (let i = 0; i < 5; i++) {
        const sx = rLeft + rW * 0.12 + i * rW * 0.17 + Math.sin(frame * 0.025 + i * 1.7) * 6;
        const sy = rTop + rH * (0.2 + sr(i * 17) * 0.6);
        ctx.globalAlpha = 0.08 + Math.sin(frame * 0.04 + i) * 0.05;
        ctx.fillStyle = '#c0e8ff';
        ctx.beginPath();
        ctx.ellipse(sx, sy, 12 + sr(i * 7) * 8, 2, 0, 0, Math.PI * 2);
        ctx.fill();
    }
    ctx.restore();

    // Stones
    for (const stone of stones) {
        const [sx, sy] = toScreen(stone.nx, stone.ny, 0.15, W, H, camX, camY);
        if (sx < -20 || sx > W + 20) continue;
        ctx.save();
        ctx.translate(sx, sy);
        ctx.rotate(stone.rot);
        const shade = Math.floor(stone.shade * 255);
        ctx.fillStyle = `rgb(${shade},${shade - 5},${shade - 10})`;
        ctx.beginPath();
        ctx.ellipse(0, 0, stone.rx, stone.ry, 0, 0, Math.PI * 2);
        ctx.fill();
        // Highlight
        ctx.globalAlpha = 0.25;
        ctx.fillStyle = '#b0b0b0';
        ctx.beginPath();
        ctx.ellipse(-stone.rx * 0.2, -stone.ry * 0.3, stone.rx * 0.4, stone.ry * 0.3, 0, 0, Math.PI * 2);
        ctx.fill();
        ctx.restore();
    }
}

function drawBridge(ctx, W, H, frame, camX, camY) {
    const depth = 0.15;
    const bLeft = groveX(0.24) * W - camX * depth;
    const bRight = groveX(0.75) * W - camX * depth;
    const bW = bRight - bLeft;
    const rCenter = groveY(0.60) * H - camY * depth;
    const archH = 18;
    const deckThick = 6;
    const railH = 14;
    const postCount = 7;

    const archY = (t) => rCenter - archH * 4 * t * (1 - t);

    // Support posts (behind deck)
    ctx.strokeStyle = '#5a3a1a';
    ctx.lineWidth = 4;
    for (let i = 0; i <= postCount; i++) {
        const t = i / postCount;
        const x = bLeft + t * bW;
        const y = archY(t);
        ctx.beginPath();
        ctx.moveTo(x, y + deckThick);
        ctx.lineTo(x, y + deckThick + 18);
        ctx.stroke();
    }

    // Deck surface
    ctx.fillStyle = '#9B7328';
    ctx.beginPath();
    ctx.moveTo(bLeft, archY(0));
    for (let t = 0; t <= 1; t += 0.015) {
        ctx.lineTo(bLeft + t * bW, archY(t));
    }
    for (let t = 1; t >= 0; t -= 0.015) {
        ctx.lineTo(bLeft + t * bW, archY(t) + deckThick);
    }
    ctx.closePath();
    ctx.fill();

    // Deck shadow
    ctx.save();
    ctx.globalAlpha = 0.15;
    ctx.fillStyle = '#000';
    ctx.beginPath();
    ctx.moveTo(bLeft, archY(0) + deckThick);
    for (let t = 0; t <= 1; t += 0.015) {
        ctx.lineTo(bLeft + t * bW, archY(t) + deckThick);
    }
    for (let t = 1; t >= 0; t -= 0.015) {
        ctx.lineTo(bLeft + t * bW, archY(t) + deckThick + 8);
    }
    ctx.closePath();
    ctx.fill();
    ctx.restore();

    // Plank lines
    ctx.strokeStyle = '#7a5518';
    ctx.lineWidth = 0.8;
    const plankN = 28;
    for (let i = 1; i < plankN; i++) {
        const t = i / plankN;
        const x = bLeft + t * bW;
        ctx.beginPath();
        ctx.moveTo(x, archY(t));
        ctx.lineTo(x, archY(t) + deckThick);
        ctx.stroke();
    }

    // Railing posts
    ctx.strokeStyle = '#6a4a12';
    ctx.lineWidth = 2.5;
    for (let i = 0; i <= postCount; i++) {
        const t = i / postCount;
        const x = bLeft + t * bW;
        ctx.beginPath();
        ctx.moveTo(x, archY(t));
        ctx.lineTo(x, archY(t) - railH);
        ctx.stroke();
    }

    // Top rail
    ctx.lineWidth = 2.8;
    ctx.strokeStyle = '#7a5a1a';
    ctx.beginPath();
    for (let t = 0; t <= 1; t += 0.015) {
        const x = bLeft + t * bW;
        const y = archY(t) - railH;
        t === 0 ? ctx.moveTo(x, y) : ctx.lineTo(x, y);
    }
    ctx.stroke();

    // Mid rail
    ctx.lineWidth = 1.5;
    ctx.beginPath();
    for (let t = 0; t <= 1; t += 0.015) {
        const x = bLeft + t * bW;
        const y = archY(t) - railH * 0.5;
        t === 0 ? ctx.moveTo(x, y) : ctx.lineTo(x, y);
    }
    ctx.stroke();
}

function drawTree(ctx, x, y, tree, frame, hasFruits, streak) {
    const sway = Math.sin(frame * tree.swayOff * 0.01 + tree.swayOff) * 2;
    const tH = tree.trunkH;
    const tW = tree.trunkW;
    const cR = tree.canopyR;

    ctx.save();
    ctx.globalAlpha = 0.22;
    ctx.fillStyle = '#1f3519';
    ctx.beginPath();
    ctx.ellipse(x, y + 2, cR * 0.72, cR * 0.18, 0, 0, Math.PI * 2);
    ctx.fill();
    ctx.restore();

    // Trunk
    ctx.fillStyle = '#5a3a1a';
    ctx.beginPath();
    ctx.moveTo(x - tW * 0.5, y);
    ctx.lineTo(x - tW * 0.35 + sway * 0.3, y - tH);
    ctx.lineTo(x + tW * 0.35 + sway * 0.3, y - tH);
    ctx.lineTo(x + tW * 0.5, y);
    ctx.closePath();
    ctx.fill();

    // Trunk texture
    ctx.save();
    ctx.globalAlpha = 0.2;
    ctx.strokeStyle = '#3a2a10';
    ctx.lineWidth = 0.8;
    for (let i = 1; i < 4; i++) {
        const ty = y - tH * (i / 4);
        const tw = tW * (0.5 - i * 0.05);
        ctx.beginPath();
        ctx.moveTo(x - tw + sway * 0.3 * (i / 4), ty);
        ctx.lineTo(x + tw + sway * 0.3 * (i / 4), ty);
        ctx.stroke();
    }
    ctx.restore();

    // Canopy (multiple overlapping circles)
    const cx = x + sway;
    const cy = y - tH;
    const layers = [
        { dx: 0, dy: -cR * 0.3, r: cR, lit: tree.lit },
        { dx: -cR * 0.5, dy: 0, r: cR * 0.8, lit: tree.lit - 3 },
        { dx: cR * 0.5, dy: 0, r: cR * 0.8, lit: tree.lit - 2 },
        { dx: -cR * 0.2, dy: -cR * 0.6, r: cR * 0.7, lit: tree.lit + 2 },
        { dx: cR * 0.2, dy: -cR * 0.5, r: cR * 0.65, lit: tree.lit + 1 },
    ];

    // Shadow under canopy
    ctx.save();
    ctx.globalAlpha = 0.12;
    ctx.fillStyle = '#000';
    ctx.beginPath();
    ctx.ellipse(cx, cy + cR * 0.3, cR * 1.1, cR * 0.3, 0, 0, Math.PI * 2);
    ctx.fill();
    ctx.restore();

    for (const l of layers) {
        const g = ctx.createRadialGradient(
            cx + l.dx, cy + l.dy - l.r * 0.2, 0,
            cx + l.dx, cy + l.dy, l.r
        );
        g.addColorStop(0, `hsl(${tree.hue}, ${tree.sat}%, ${l.lit + 8}%)`);
        g.addColorStop(0.6, `hsl(${tree.hue}, ${tree.sat}%, ${l.lit}%)`);
        g.addColorStop(1, `hsl(${tree.hue - 10}, ${tree.sat - 5}%, ${l.lit - 5}%)`);
        ctx.fillStyle = g;
        ctx.beginPath();
        ctx.arc(cx + l.dx, cy + l.dy, l.r, 0, Math.PI * 2);
        ctx.fill();
    }

    // Fruits
    if (hasFruits) {
        for (let i = 0; i < tree.fruitCount; i++) {
            const fs = tree.plantedDay * 3 + i * 47;
            const angle = (i / tree.fruitCount) * Math.PI * 2 + sr(fs) * 0.5;
            const dist = cR * (0.5 + sr(fs + 1) * 0.35);
            const fx = cx + Math.cos(angle) * dist;
            const fy = cy + Math.sin(angle) * dist * 0.7;
            const fSize = 3.5 + sr(fs + 2) * 2;

            ctx.fillStyle = `hsl(${tree.fruitHue + i * 30}, 72%, 52%)`;
            ctx.beginPath();
            ctx.arc(fx, fy, fSize, 0, Math.PI * 2);
            ctx.fill();

            // Highlight
            ctx.save();
            ctx.globalAlpha = 0.4;
            ctx.fillStyle = '#fff';
            ctx.beginPath();
            ctx.arc(fx - fSize * 0.25, fy - fSize * 0.25, fSize * 0.35, 0, Math.PI * 2);
            ctx.fill();
            ctx.restore();
        }
    }
}

function drawPlant(ctx, x, y, plant, frame, hasFlower) {
    const sway = Math.sin(frame * plant.swaySpd + plant.swayOff) * 3;
    const h = plant.stemH;

    ctx.save();
    ctx.globalAlpha = 0.28;
    ctx.fillStyle = '#2b4a20';
    ctx.beginPath();
    ctx.ellipse(x, y + 1.5, 6, 2.2, 0, 0, Math.PI * 2);
    ctx.fill();
    ctx.restore();

    // Stem
    ctx.strokeStyle = '#3a7a28';
    ctx.lineWidth = 1.5;
    ctx.beginPath();
    ctx.moveTo(x, y);
    ctx.quadraticCurveTo(x + sway * 0.5, y - h * 0.5, x + sway, y - h);
    ctx.stroke();

    // Leaves
    ctx.fillStyle = '#4a8a35';
    const leafY = y - h * 0.45;
    const leafX = x + sway * 0.3;
    ctx.save();
    ctx.translate(leafX, leafY);
    ctx.rotate(0.4 + sway * 0.03);
    ctx.beginPath();
    ctx.ellipse(4, 0, 5, 2.5, 0, 0, Math.PI * 2);
    ctx.fill();
    ctx.restore();

    ctx.save();
    ctx.translate(leafX, leafY + 3);
    ctx.rotate(-0.5 + sway * 0.03);
    ctx.beginPath();
    ctx.ellipse(-4, 0, 4.5, 2, 0, 0, Math.PI * 2);
    ctx.fill();
    ctx.restore();

    // Flower
    if (hasFlower) {
        const fx = x + sway;
        const fy = y - h;
        const fs = plant.flowerSize;
        const petals = 5;

        ctx.fillStyle = plant.flowerColor;
        for (let i = 0; i < petals; i++) {
            const a = (i / petals) * Math.PI * 2 - Math.PI / 2;
            const px = fx + Math.cos(a) * fs * 0.35;
            const py = fy + Math.sin(a) * fs * 0.35;
            ctx.beginPath();
            ctx.arc(px, py, fs * 0.32, 0, Math.PI * 2);
            ctx.fill();
        }
        ctx.fillStyle = '#ffd700';
        ctx.beginPath();
        ctx.arc(fx, fy, fs * 0.2, 0, Math.PI * 2);
        ctx.fill();
    }
}

function drawFishShape(ctx, x, y, size, frame, seed) {
    const wobble = Math.sin(frame * 0.04 + seed) * 3;
    const dir = sr(seed + 100) > 0.5 ? 1 : -1;

    ctx.save();
    ctx.translate(x + wobble, y);
    ctx.scale(dir, 1);

    // Body
    ctx.fillStyle = '#e8a030';
    ctx.beginPath();
    ctx.ellipse(0, 0, size * 0.6, size * 0.3, 0, 0, Math.PI * 2);
    ctx.fill();

    // Tail
    ctx.beginPath();
    ctx.moveTo(-size * 0.5, 0);
    ctx.lineTo(-size * 0.85, -size * 0.25);
    ctx.lineTo(-size * 0.85, size * 0.25);
    ctx.closePath();
    ctx.fill();

    // Eye
    ctx.fillStyle = '#000';
    ctx.beginPath();
    ctx.arc(size * 0.25, -size * 0.05, 1.5, 0, Math.PI * 2);
    ctx.fill();

    // Fin
    ctx.save();
    ctx.globalAlpha = 0.5;
    ctx.fillStyle = '#d09028';
    ctx.beginPath();
    ctx.ellipse(0, -size * 0.2, size * 0.15, size * 0.1, -0.3, 0, Math.PI * 2);
    ctx.fill();
    ctx.restore();

    ctx.restore();
}

function drawLeg(ctx, x1, y1, x2, y2, color, width = 2) {
    ctx.strokeStyle = color;
    ctx.lineWidth = width;
    ctx.lineCap = 'round';
    ctx.beginPath();
    ctx.moveTo(x1, y1);
    ctx.lineTo(x2, y2);
    ctx.stroke();
}

function drawBodyAnimal(ctx, x, y, size, frame, animal) {
    const t = frame * animal.idleSpd + animal.idleOff;
    const walk = Math.sin(t * 2.2);
    const dir = sr(animal.day + 19) > 0.5 ? 1 : -1;
    const move = Math.sin(t * 0.45) * 16;
    const groundY = y;
    const px = x + move;
    const scale = size / 24;

    const palettes = {
        Lion: ['#b9823c', '#704a24', '#d3a15a'],
        Wolf: ['#8b8f8f', '#4d5659', '#c9cdca'],
        Elephant: ['#9fa5a7', '#6c7478', '#c7cbca'],
        Dog: ['#a46a3f', '#5f3c24', '#d7a56e'],
    };
    const [body, dark, light] = palettes[animal.name] || ['#9a7b55', '#4d3a2a', '#cab08a'];

    ctx.save();
    ctx.translate(px, groundY);
    ctx.scale(dir * scale, scale);

    ctx.globalAlpha = 0.24;
    ctx.fillStyle = '#1d3017';
    ctx.beginPath();
    ctx.ellipse(0, 3, 17, 4, 0, 0, Math.PI * 2);
    ctx.fill();
    ctx.globalAlpha = 1;

    drawLeg(ctx, -7, -1, -9 + walk * 2, 7, dark, 2.3);
    drawLeg(ctx, -1, 0, -2 - walk * 2, 7, dark, 2.3);
    drawLeg(ctx, 6, -1, 8 - walk * 2, 7, dark, 2.3);
    drawLeg(ctx, 11, 0, 11 + walk * 2, 7, dark, 2.3);

    ctx.fillStyle = body;
    ctx.beginPath();
    ctx.ellipse(0, -5, 14, 8, 0, 0, Math.PI * 2);
    ctx.fill();

    ctx.fillStyle = light;
    ctx.beginPath();
    ctx.ellipse(4, -4, 7, 4, 0, 0, Math.PI * 2);
    ctx.fill();

    if (animal.name === 'Elephant') {
        ctx.fillStyle = body;
        ctx.beginPath(); ctx.ellipse(13, -10, 7, 7, 0, 0, Math.PI * 2); ctx.fill();
        ctx.beginPath(); ctx.ellipse(8, -10, 5, 7, 0.35, 0, Math.PI * 2); ctx.fill();
        ctx.strokeStyle = body; ctx.lineWidth = 4; ctx.lineCap = 'round';
        ctx.beginPath(); ctx.moveTo(17, -7); ctx.quadraticCurveTo(20, -1, 16, 4); ctx.stroke();
    } else {
        ctx.fillStyle = body;
        ctx.beginPath(); ctx.ellipse(14, -10, 6, 5, 0, 0, Math.PI * 2); ctx.fill();
        ctx.fillStyle = dark;
        ctx.beginPath(); ctx.moveTo(11, -14); ctx.lineTo(13, -20); ctx.lineTo(16, -14); ctx.fill();
        ctx.beginPath(); ctx.moveTo(16, -14); ctx.lineTo(19, -19); ctx.lineTo(20, -12); ctx.fill();
        if (animal.name === 'Lion') {
            ctx.globalAlpha = 0.45;
            ctx.beginPath(); ctx.arc(14, -10, 8, 0, Math.PI * 2); ctx.fill();
            ctx.globalAlpha = 1;
        }
        ctx.strokeStyle = dark; ctx.lineWidth = 2;
        ctx.beginPath(); ctx.moveTo(-13, -6); ctx.quadraticCurveTo(-19, -12, -18, -17); ctx.stroke();
    }

    ctx.fillStyle = '#172016';
    ctx.beginPath(); ctx.arc(16, -11, 1, 0, Math.PI * 2); ctx.fill();
    ctx.restore();
}

function drawSmallAnimal(ctx, x, y, size, frame, animal) {
    const t = frame * animal.idleSpd + animal.idleOff;
    const crawl = Math.sin(t * 3) * 3;
    const px = x + Math.sin(t * 0.7) * 10;
    const scale = size / 12;
    const colors = {
        Crow: '#222827',
        Hoopoe: '#c98b45',
        Ant: '#2a1b18',
        Bee: '#b78b28',
        Spider: '#34302f',
        Locust: '#5f7b35',
        Frog: '#6aa64c',
    };
    const color = colors[animal.name] || '#72543a';

    ctx.save();
    ctx.translate(px, y);
    ctx.scale(scale, scale);
    ctx.globalAlpha = 0.22;
    ctx.fillStyle = '#1d3017';
    ctx.beginPath(); ctx.ellipse(0, 3, 9, 2.5, 0, 0, Math.PI * 2); ctx.fill();
    ctx.globalAlpha = 1;

    if (animal.name === 'Crow' || animal.name === 'Hoopoe') {
        ctx.fillStyle = color;
        ctx.beginPath(); ctx.ellipse(0, -4, 8, 5, 0, 0, Math.PI * 2); ctx.fill();
        ctx.beginPath(); ctx.ellipse(7, -7, 4, 4, 0, 0, Math.PI * 2); ctx.fill();
        ctx.fillStyle = '#c69b45';
        ctx.beginPath(); ctx.moveTo(10, -7); ctx.lineTo(16, -5); ctx.lineTo(10, -3); ctx.fill();
        if (animal.name === 'Hoopoe') {
            ctx.strokeStyle = '#8a4f26'; ctx.lineWidth = 1.2;
            ctx.beginPath(); ctx.moveTo(6, -11); ctx.lineTo(4, -16); ctx.stroke();
            ctx.beginPath(); ctx.moveTo(8, -11); ctx.lineTo(9, -16); ctx.stroke();
        }
        drawLeg(ctx, -2, 0, -3, 5, '#3d2818', 1.4);
        drawLeg(ctx, 3, 0, 4, 5, '#3d2818', 1.4);
    } else if (animal.name === 'Frog') {
        const hop = Math.abs(Math.sin(t * 2)) * 3;
        ctx.translate(0, -hop);
        ctx.fillStyle = color;
        ctx.beginPath(); ctx.ellipse(0, -4, 8, 5, 0, 0, Math.PI * 2); ctx.fill();
        ctx.beginPath(); ctx.arc(-4, -9, 2, 0, Math.PI * 2); ctx.fill();
        ctx.beginPath(); ctx.arc(4, -9, 2, 0, Math.PI * 2); ctx.fill();
        ctx.fillStyle = '#14220f';
        ctx.beginPath(); ctx.arc(-4, -9, 0.8, 0, Math.PI * 2); ctx.fill();
        ctx.beginPath(); ctx.arc(4, -9, 0.8, 0, Math.PI * 2); ctx.fill();
    } else {
        ctx.fillStyle = color;
        ctx.beginPath(); ctx.ellipse(-3, -4, 5, 3.2, 0, 0, Math.PI * 2); ctx.fill();
        ctx.beginPath(); ctx.ellipse(4, -4, 5, 3, 0, 0, Math.PI * 2); ctx.fill();
        if (animal.name === 'Bee') {
            ctx.strokeStyle = '#312713'; ctx.lineWidth = 1;
            drawLeg(ctx, -2, -7, -2, -1, '#312713', 1);
            ctx.globalAlpha = 0.35;
            ctx.fillStyle = '#e8f3d6';
            ctx.beginPath(); ctx.ellipse(-2, -8, 3, 2, -0.5, 0, Math.PI * 2); ctx.fill();
            ctx.beginPath(); ctx.ellipse(3, -8, 3, 2, 0.5, 0, Math.PI * 2); ctx.fill();
            ctx.globalAlpha = 1;
        }
        for (let i = -1; i <= 1; i++) {
            drawLeg(ctx, -2 + i * 4, -2, -4 + i * 4 + crawl, 3, '#33251c', 1);
        }
    }
    ctx.restore();
}

function drawAnimal(ctx, x, y, animal, frame) {
    if (['Lion', 'Wolf', 'Elephant', 'Dog'].includes(animal.name)) {
        drawBodyAnimal(ctx, x, y, animal.size, frame, animal);
    } else {
        drawSmallAnimal(ctx, x, y, animal.size, frame, animal);
    }
}

// ═══════════════════════════════════════════════════════════════
// COMPONENT
// ═══════════════════════════════════════════════════════════════
const Forest = ({ streak = 0, onClose }) => {
    const canvasRef = useRef(null);
    const [visible, setVisible] = useState(false);

    const stateRef = useRef({
        W: 0, H: 0,
        camX: 0, camY: 0,
        frame: 0,
        keys: {},
        touch: { a: false, sx: 0, sy: 0, scx: 0, scy: 0 },
        PLANTS: prebuildPlants(),
        TREES: prebuildTrees(),
        ANIMALS: prebuildAnimals(),
        STONES: prebuildStones(),
        animId: null,
    });

    const onCloseRef = useRef(onClose);
    onCloseRef.current = onClose;

    // ── Body scroll lock + fade in ──────────────────────
    useEffect(() => {
        const scrollY = window.scrollY;
        const body = document.body;
        const orig = {
            overflow: body.style.overflow,
            position: body.style.position,
            top: body.style.top,
            width: body.style.width,
        };
        body.style.overflow = 'hidden';
        body.style.position = 'fixed';
        body.style.top = `-${scrollY}px`;
        body.style.width = '100%';
        const t = setTimeout(() => setVisible(true), 50);
        return () => {
            clearTimeout(t);
            Object.assign(body.style, orig);
            window.scrollTo(0, scrollY);
        };
    }, []);

    // ── Resize ──────────────────────────────────────────
    useEffect(() => {
        const handleResize = () => {
            const c = canvasRef.current;
            if (!c) return;
            stateRef.current.W = c.width = window.innerWidth;
            stateRef.current.H = c.height = window.innerHeight;
        };
        handleResize();
        window.addEventListener('resize', handleResize);
        return () => window.removeEventListener('resize', handleResize);
    }, []);

    // ── Keyboard ───────────────────────────────────────
    useEffect(() => {
        const down = (e) => {
            if (['ArrowLeft', 'ArrowRight', 'ArrowUp', 'ArrowDown', 'Tab'].includes(e.key)) {
                e.preventDefault(); e.stopPropagation();
            }
            if (e.key === 'Escape') { e.preventDefault(); e.stopPropagation(); onCloseRef.current?.(); return; }
            stateRef.current.keys[e.key] = true;
        };
        const up = (e) => { e.stopPropagation(); delete stateRef.current.keys[e.key]; };
        window.addEventListener('keydown', down, true);
        window.addEventListener('keyup', up, true);
        return () => { window.removeEventListener('keydown', down, true); window.removeEventListener('keyup', up, true); };
    }, []);

    // ── Touch ──────────────────────────────────────────
    useEffect(() => {
        const c = canvasRef.current;
        if (!c) return;
        const MAX = 120;
        const ts = (e) => { e.stopPropagation(); const t = e.touches[0]; const s = stateRef.current; s.touch = { a: true, sx: t.clientX, sy: t.clientY, scx: s.camX, scy: s.camY }; };
        const tm = (e) => { e.preventDefault(); e.stopPropagation(); const s = stateRef.current; if (!s.touch.a) return; const t = e.touches[0]; s.camX = clamp(s.touch.scx - (t.clientX - s.touch.sx) * 0.4, -MAX, MAX); s.camY = clamp(s.touch.scy - (t.clientY - s.touch.sy) * 0.4, -MAX, MAX); };
        const te = (e) => { e.stopPropagation(); stateRef.current.touch.a = false; };
        c.addEventListener('touchstart', ts, { passive: true });
        c.addEventListener('touchmove', tm, { passive: false });
        c.addEventListener('touchend', te, { passive: true });
        return () => { c.removeEventListener('touchstart', ts); c.removeEventListener('touchmove', tm); c.removeEventListener('touchend', te); };
    }, []);

    // ── Animation loop ────────────────────────────────
    useEffect(() => {
        const MAX = 120, SPD = 2.8;
        const tick = () => {
            const c = canvasRef.current;
            if (!c) { stateRef.current.animId = requestAnimationFrame(tick); return; }
            const ctx = c.getContext('2d');
            const s = stateRef.current;
            const { W, H, keys } = s;
            if (!W || !H) { s.animId = requestAnimationFrame(tick); return; }

            // Camera
            if (keys['ArrowLeft'])  s.camX = clamp(s.camX - SPD, -MAX, MAX);
            if (keys['ArrowRight']) s.camX = clamp(s.camX + SPD, -MAX, MAX);
            if (keys['ArrowUp'])    s.camY = clamp(s.camY - SPD, -MAX, MAX);
            if (keys['ArrowDown'])  s.camY = clamp(s.camY + SPD, -MAX, MAX);
            if (!keys['ArrowLeft'] && !keys['ArrowRight']) s.camX *= 0.96;
            if (!keys['ArrowUp'] && !keys['ArrowDown']) s.camY *= 0.96;

            s.frame++;
            const frame = s.frame;
            const { camX, camY } = s;

            // ═══════════════════════════════════════════
            // 1. SKY + CLOUDS
            // ═══════════════════════════════════════════
            ctx.clearRect(0, 0, W, H);

            // ═══════════════════════════════════════════
            // 2. MOUNTAINS (3 layers)
            // ═══════════════════════════════════════════
            // Background layers intentionally omitted for a quieter planted grove.

            // ═══════════════════════════════════════════
            // 3. GROUND
            // ═══════════════════════════════════════════
            drawGround(ctx, W, H, camX, camY);

            // Grass tufts — far
            drawGrassTufts(ctx, W, H, frame, camX, camY, groveY(0.18), groveY(0.92), 65, 500);
            // Grass tufts — near
            drawGrassTufts(ctx, W, H, frame, camX, camY, groveY(0.58), groveY(0.94), 60, 800);

            // ═══════════════════════════════════════════
            // 4. FAR TREES
            // ═══════════════════════════════════════════
            const treeCount = Math.min(Math.floor(streak / 7), 52);
            for (let i = 0; i < treeCount; i++) {
                const tree = s.TREES[i];
                if (tree.bank !== 'far') continue;
                const [x, y] = toScreen(tree.nx, tree.ny, tree.depth, W, H, camX, camY);
                if (x < -80 || x > W + 80) continue;
                const hasFruits = streak >= tree.plantedDay + 7;
                drawTree(ctx, x, y, tree, frame, hasFruits, streak);
            }

            // ═══════════════════════════════════════════
            // 5. FAR PLANTS
            // ═══════════════════════════════════════════
            const plantCount = Math.min(streak, 365);
            const plantStep = Math.max(1, Math.ceil(plantCount / 160));
            for (let i = 0; i < plantCount; i += plantStep) {
                const p = s.PLANTS[i];
                if (p.bank !== 'far') continue;
                const [x, y] = toScreen(p.nx, p.ny, p.depth, W, H, camX, camY);
                if (x < -15 || x > W + 15) continue;
                const hasFlower = streak >= p.day + 1;
                drawPlant(ctx, x, y, p, frame, hasFlower);
            }

            // ═══════════════════════════════════════════
            // 6. RIVER (180+ days)
            // ═══════════════════════════════════════════
            const showRiver = streak >= 180;
            if (showRiver) {
                drawRiver(ctx, W, H, frame, camX, camY, s.STONES);

                // Fish in river (187+)
                if (streak >= 187) {
                    const fish = s.ANIMALS.find(a => a.name === 'Fish');
                    if (fish) {
                        // Draw multiple fish
                        for (let fi = 0; fi < 4; fi++) {
                            const fs = fish.day * 7 + fi * 43;
                            const fnx = fish.nx + (sr(fs) - 0.5) * 0.18 + Math.sin(frame * 0.012 + fs) * 0.05;
                            const fny = fish.ny + (sr(fs + 1) - 0.5) * 0.018;
                            const [fsx, fsy] = toScreen(fnx, fny, fish.depth, W, H, camX, camY);
                            if (fsx > -20 && fsx < W + 20) {
                                drawFishShape(ctx, fsx, fsy, 8 + sr(fs + 2) * 5, frame, fs);
                            }
                        }
                    }
                }

                // Bridge (360+)
                if (streak >= 360) {
                    drawBridge(ctx, W, H, frame, camX, camY);
                }
            }

            // ═══════════════════════════════════════════
            // 7. NEAR TREES
            // ═══════════════════════════════════════════
            for (let i = 0; i < treeCount; i++) {
                const tree = s.TREES[i];
                if (tree.bank !== 'near') continue;
                const [x, y] = toScreen(tree.nx, tree.ny, tree.depth, W, H, camX, camY);
                if (x < -80 || x > W + 80) continue;
                const hasFruits = streak >= tree.plantedDay + 7;
                drawTree(ctx, x, y, tree, frame, hasFruits, streak);
            }

            // ═══════════════════════════════════════════
            // 8. NEAR PLANTS
            // ═══════════════════════════════════════════
            for (let i = 0; i < plantCount; i += plantStep) {
                const p = s.PLANTS[i];
                if (p.bank !== 'near') continue;
                const [x, y] = toScreen(p.nx, p.ny, p.depth, W, H, camX, camY);
                if (x < -15 || x > W + 15) continue;
                const hasFlower = streak >= p.day + 1;
                drawPlant(ctx, x, y, p, frame, hasFlower);
            }

            // ═══════════════════════════════════════════
            // 9. LAND ANIMALS (excluding fish/frog)
            // ═══════════════════════════════════════════
            for (const animal of s.ANIMALS) {
                if (animal.name === 'Fish' || animal.name === 'Frog') continue;
                if (streak < animal.day) continue;
                const [ax, ay] = toScreen(animal.nx, animal.ny, animal.depth, W, H, camX, camY);
                if (ax < -40 || ax > W + 40) continue;

                drawAnimal(ctx, ax, ay, animal, frame);
            }

            // Frog near river bank (194+)
            if (streak >= 194) {
                const frog = s.ANIMALS.find(a => a.name === 'Frog');
                if (frog) {
                    const [fx, fy] = toScreen(frog.nx, frog.ny, frog.depth, W, H, camX, camY);
                    drawAnimal(ctx, fx, fy, frog, frame);
                }
            }

            // ═══════════════════════════════════════════
            // 10. FIREFLIES
            // ═══════════════════════════════════════════
            // Fireflies are omitted in this calmer version.

            // ═══════════════════════════════════════════
            // 11. FOREGROUND GRASS BLADES
            // ═══════════════════════════════════════════
            // Foreground blades are omitted so the planted area stays tidy.

            // ═══════════════════════════════════════════
            // 12. VIGNETTE
            // ═══════════════════════════════════════════
            const vig = ctx.createRadialGradient(W / 2, H / 2, Math.min(W, H) * 0.35, W / 2, H / 2, Math.max(W, H) * 0.75);
            vig.addColorStop(0, 'rgba(0,0,0,0)');
            vig.addColorStop(1, 'rgba(0,0,0,0.25)');
            ctx.fillStyle = vig;
            ctx.fillRect(0, 0, W, H);

            s.animId = requestAnimationFrame(tick);
        };

        const animState = stateRef.current;
        animState.animId = requestAnimationFrame(tick);
        return () => { if (animState.animId) cancelAnimationFrame(animState.animId); };
    }, [streak]);

    // ── HUD ───────────────────────────────────────────
    const hud = useMemo(() => {
        const nP = Math.min(streak, 365);
        const nFl = Math.min(Math.max(streak - 1, 0), 364);
        const nT = Math.min(Math.floor(streak / 7), 52);
        const nFr = Math.min(Math.floor((streak - 14) / 7), 51);
        const nA = ANIMAL_DEFS.filter(a => streak >= a.day).length;
        const river = streak >= 180;
        const fish = streak >= 187;
        const frogs = streak >= 194;
        const bridge = streak >= 360;

        let cur = MILESTONES[0];
        for (const m of MILESTONES) if (streak >= m.d) cur = m;
        const nxt = MILESTONES.find(m => streak < m.d);

        return { nP, nFl, nT, nFr, nA, river, fish, frogs, bridge, cur, nxt };
    }, [streak]);

    const counters = [
        [hud.nP, 'Plants'],
        [hud.nT, 'Trees'],
        [hud.nA, 'Animals'],
        [hud.river ? 'Yes' : '—', 'River'],
        [hud.fish ? 'Yes' : '—', 'Fish'],
        [hud.frogs ? 'Yes' : '—', 'Frogs'],
        [hud.bridge ? 'Yes' : '—', 'Bridge'],
    ];

    return (
        <div
            style={{
                position: 'fixed', inset: 0, zIndex: 99999,
                background: '#2d5a22', overflow: 'hidden',
                pointerEvents: 'all',
                opacity: visible ? 1 : 0,
                transition: 'opacity 0.6s ease-out'
            }}
            onClick={e => e.stopPropagation()}
            onMouseDown={e => e.stopPropagation()}
            onWheel={e => e.stopPropagation()}
        >
            <canvas
                ref={canvasRef}
                style={{ display: 'block', position: 'fixed', top: 0, left: 0, width: '100vw', height: '100vh' }}
            />

            {/* Top bar */}
            <div style={{
                position: 'fixed', top: 0, left: 0, right: 0, zIndex: 20,
                padding: '10px 20px',
                background: 'linear-gradient(180deg, rgba(0,0,0,0.6) 0%, transparent 100%)',
                display: 'flex', justifyContent: 'space-between', alignItems: 'center',
                pointerEvents: 'none'
            }}>
                <div style={{ display: 'flex', gap: 14, flexWrap: 'wrap' }}>
                    {counters.filter(([, label]) => !['Fish', 'Frogs'].includes(label)).map(([val, label]) => (
                        <div key={label} style={{ textAlign: 'center' }}>
                            <div style={{
                                fontSize: 14, fontWeight: 'bold', color: '#fff',
                                textShadow: '0 0 8px rgba(100,180,80,.8)'
                            }}>
                                {val}
                            </div>
                            <div style={{
                                fontSize: 8, color: 'rgba(180,220,160,.7)',
                                letterSpacing: '.08em', textTransform: 'uppercase'
                            }}>
                                {label}
                            </div>
                        </div>
                    ))}
                </div>
                <button
                    onClick={e => { e.stopPropagation(); onClose(); }}
                    style={{
                        pointerEvents: 'all', cursor: 'pointer',
                        background: 'rgba(0,0,0,.45)',
                        border: '1px solid rgba(100,180,80,.3)',
                        borderRadius: 10, padding: '6px 14px',
                        color: 'rgba(180,220,160,.9)', fontSize: 13,
                        backdropFilter: 'blur(6px)', fontFamily: 'Georgia, serif'
                    }}
                >
                    ✕ Close
                </button>
            </div>

            {/* Bottom HUD */}
            <div style={{
                position: 'fixed', bottom: 0, left: 0, right: 0, zIndex: 20,
                padding: '12px 22px',
                background: 'linear-gradient(0deg, rgba(0,0,0,.6) 0%, transparent 100%)',
                display: 'flex', justifyContent: 'space-between', alignItems: 'flex-end',
                pointerEvents: 'none'
            }}>
                <div>
                    <div style={{
                        fontSize: 22, fontWeight: 'bold', color: '#fff',
                        letterSpacing: '.07em',
                        textShadow: '0 0 16px rgba(100,180,80,.8)'
                    }}>
                        {streak} Day{streak !== 1 ? 's' : ''}
                    </div>
                    <div style={{ fontSize: 12, color: 'rgba(180,220,160,.8)', lineHeight: 1.75 }}>
                        {hud.cur.e} {hud.cur.l}
                    </div>
                    <div style={{ fontSize: 11, color: 'rgba(140,190,120,.6)' }}>
                        {hud.nxt
                            ? `${hud.nxt.e} ${hud.nxt.l} in ${hud.nxt.d - streak} day${(hud.nxt.d - streak) !== 1 ? 's' : ''}`
                            : '🌿 Full Ancient Grove achieved — 365 plants, 52 trees, 12 animals, river & bridge'
                        }
                    </div>
                </div>
                <div style={{
                    textAlign: 'right', fontSize: 11,
                    color: 'rgba(140,190,120,.5)',
                    fontStyle: 'italic', lineHeight: 1.7
                }}>
                    Arrow keys · explore the grove<br />
                    Esc to close
                </div>
            </div>
        </div>
    );
};

Forest.isCanvasScene = true;

export default Forest;
